module top_module(clk, rst, count);input clk, rst;
   output reg [3:0] count;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
     begin
       if(rst == 1)
         count <= 0;
       else
         count <= count + 1;
     end
endmodule
